
'use client';

import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { MoreHorizontal, UserPlus } from "lucide-react";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuLabel, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';

const initialStudents = [
  { id: 'S101', name: 'Alice Johnson', avatar: 'https://placehold.co/40x40.png', route: 'North Route', parent: 'Carol Johnson', status: 'Enrolled' },
  { id: 'S102', name: 'Bob Williams', avatar: 'https://placehold.co/40x40.png', route: 'North Route', parent: 'David Williams', status: 'Enrolled' },
  { id: 'S103', name: 'Charlie Brown', avatar: 'https://placehold.co/40x40.png', route: 'South Route', parent: 'Laura Brown', status: 'Enrolled' },
  { id: 'S104', name: 'Diana Miller', avatar: 'https://placehold.co/40x40.png', route: 'East County', parent: 'Tom Miller', status: 'Enrolled' },
  { id: 'S105', name: 'Ethan Davis', avatar: 'https://placehold.co/40x40.png', route: 'N/A', parent: 'Susan Davis', status: 'Withdrawn' },
];

export default function StudentManagementPage() {
  const [students, setStudents] = useState(initialStudents);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const { toast } = useToast();

  const handleAddStudent = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const formData = new FormData(event.currentTarget);
    const newStudent = {
      id: `S${students.length + 101}`,
      name: formData.get('studentName') as string,
      avatar: 'https://placehold.co/40x40.png',
      route: 'N/A',
      parent: formData.get('parentName') as string,
      status: 'Enrolled',
    };
    setStudents(prev => [...prev, newStudent]);
    setIsDialogOpen(false);
    toast({
        title: "Student Added",
        description: `${newStudent.name} has been successfully enrolled.`,
    });
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold font-headline">Student Management</h1>
          <p className="text-muted-foreground">Manage student enrollment for bus services.</p>
        </div>
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogTrigger asChild>
            <Button>
              <UserPlus className="mr-2 h-4 w-4" /> Add New Student
            </Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Add New Student</DialogTitle>
              <DialogDescription>Enter the student and parent details.</DialogDescription>
            </DialogHeader>
            <form onSubmit={handleAddStudent}>
              <div className="grid gap-4 py-4">
                <div className="grid grid-cols-4 items-center gap-4">
                  <Label htmlFor="studentName" className="text-right">Student Name</Label>
                  <Input id="studentName" name="studentName" className="col-span-3" required />
                </div>
                <div className="grid grid-cols-4 items-center gap-4">
                  <Label htmlFor="parentName" className="text-right">Parent/Guardian</Label>
                  <Input id="parentName" name="parentName" className="col-span-3" required />
                </div>
              </div>
              <DialogFooter>
                <Button type="submit">Add Student</Button>
              </DialogFooter>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Student Roster</CardTitle>
          <CardDescription>A list of all students enrolled in the transport system.</CardDescription>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Student</TableHead>
                <TableHead>Assigned Route</TableHead>
                <TableHead>Parent/Guardian</TableHead>
                <TableHead>Status</TableHead>
                <TableHead><span className="sr-only">Actions</span></TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {students.map((student) => (
                <TableRow key={student.id}>
                  <TableCell className="font-medium">
                    <div className="flex items-center gap-3">
                      <Avatar>
                        <AvatarImage src={student.avatar} alt={student.name} data-ai-hint="child avatar" />
                        <AvatarFallback>{student.name.split(' ').map(n => n[0]).join('')}</AvatarFallback>
                      </Avatar>
                      <span>{student.name}</span>
                    </div>
                  </TableCell>
                  <TableCell>{student.route}</TableCell>
                  <TableCell>{student.parent}</TableCell>
                   <TableCell>
                    <Badge variant={student.status === 'Enrolled' ? 'secondary' : 'outline'}
                          className={student.status === 'Enrolled' ? 'bg-blue-500/20 text-blue-700 hover:bg-blue-500/30' : ''}>
                      {student.status}
                    </Badge>
                  </TableCell>
                  <TableCell>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button aria-haspopup="true" size="icon" variant="ghost">
                          <MoreHorizontal className="h-4 w-4" />
                          <span className="sr-only">Toggle menu</span>
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuLabel>Actions</DropdownMenuLabel>
                        <DropdownMenuItem>Edit Information</DropdownMenuItem>
                        <DropdownMenuItem>Assign to Route</DropdownMenuItem>
                        <DropdownMenuItem>View Parent Details</DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}
